import React from "react";
import { Accordion, Button, Card, Col, Container, Row } from "react-bootstrap";
import firebase from "./firebase";

function GetNotesService() {
  const [notes, setNotes] = React.useState([]);

  React.useEffect(() => {
    const fetchData = async () => {
      const db = firebase.firestore();
      const data = await db
        .collection("notes")
        .orderBy("timestamp", "desc")
        .get();
      setNotes(data.docs.map((doc) => ({ id: doc.id, ...doc.data() })));
    };
    fetchData();
  }, []);

  return (
    <div className="notes-card">
      <Accordion>
        {notes.map((note) => (
          <Card border="dark" bg="dark" text="light">
            <Accordion.Toggle as={Card.Header} eventKey={note.title}>
              <h1>{note.title}</h1>
            </Accordion.Toggle>
            <Accordion.Collapse eventKey={note.title}>
              <div className="notes-card">
                <Row className="notes-card-content">
                  <Col>
                    <p>{note.description}</p>
                  </Col>
                </Row>
                <Row className="notes-card-content">
                  <Col>
                    <p>{new Date(note.timestamp).toString()}</p>
                  </Col>
                </Row>
              </div>
            </Accordion.Collapse>
          </Card>
        ))}
      </Accordion>
    </div>
  );
}

export default GetNotesService;
