import React from "react";
import { Button, Col, Row } from "react-bootstrap";
import firebase from "../controller/firebase";

export const AbilityInput = ({ docId }) => {
  const [newName, setNewName] = React.useState();
  const [newDesc, setNewDesc] = React.useState();

  const onCreate = async (e) => {
    e.preventDefault();
    const db = firebase.firestore();
    await db.collection("characters/" + docId + "/abilities").add({
      name: newName,
      description: newDesc,
    });
    setNewDesc("");
    setNewName("");
  };

  return (
    <form onSubmit={onCreate}>
      <div className="update-card-border">
        <div className="update-card">
          <Row>
            <Col>
              <h1>Add an Ability</h1>
            </Col>
          </Row>
          <Row className="underline">
            <Col>
              <h2>Name</h2>
            </Col>
            <Col>
              <input
                className="update-card-input"
                value={newName}
                onChange={(e) => setNewName(e.target.value)}
                required
              />
            </Col>
          </Row>
          <Row className="underline">
            <h2>Description</h2>
            <textarea
              className="update-card-input text-area"
              rows={5}
              cols={5}
              value={newDesc}
              onChange={(e) => setNewDesc(e.target.value)}
              required
            />
          </Row>

          <Button
            className="update-card-button"
            type="submit"
            variant="danger"
            size="lg"
            block
          >
            Add Ability
          </Button>
        </div>
      </div>
    </form>
  );
};
